svg.script:
{
  "@context": "https://schema.org",
  "@type": "Dataset",
  "name": "Gmail by the Numbers",
  "description": "Gmail statistics sourced from Google's official blog posts and documentation, covering user scale, security protection metrics, policy impact, and sender requirements.",
  "publisher": {
    "@type": "Organization",
    "name": "InboxAlly",
    "url": "https://www.inboxally.com"
  },
  "creator": {
    "@type": "Organization",
    "name": "Google",
    "url": "https://www.google.com"
  },
  "url": "https://www.inboxally.com",
  "temporalCoverage": "2019/2026",
  "variableMeasured": [
    { "@type": "PropertyValue", "name": "Gmail active users", "value": "3 billion", "unitText": "users", "measurementTechnique": "Google official statement, January 2026" },
    { "@type": "PropertyValue", "name": "Spam/phishing/malware block rate", "value": "99.9%", "unitText": "percent", "measurementTechnique": "Google official statement, confirmed multiple times 2023-2025" },
    { "@type": "PropertyValue", "name": "Unwanted emails blocked daily", "value": "15 billion", "unitText": "emails per day", "measurementTechnique": "Google official statement, confirmed multiple times 2022-2024" },
    { "@type": "PropertyValue", "name": "Unauthenticated message reduction", "value": "75%", "unitText": "percent decrease", "measurementTechnique": "Google official statement, October 2023" },
    { "@type": "PropertyValue", "name": "Holiday scam reports reduction", "value": "35%", "unitText": "percent decrease", "measurementTechnique": "Google official statement, December 2024" }
  ]
}
